	@Test
	void saveQueryAcceptsRemainingSupportedRowCountsAndTracksShutdownState() throws Exception {
		SailRepository storageRepository = new SailRepository(new MemoryStore());
		storageRepository.init();
		QueryStorage storage = new QueryStorage(storageRepository);

		for (int rowsPerPage : List.of(0, 20, 50, 100, 200)) {
			storage.saveQuery("urn:test:repository:" + rowsPerPage, "query-" + rowsPerPage, "alice", false,
					QueryLanguage.SPARQL, "select * where { ?s ?p ?o }", false, rowsPerPage, 0);
		}

		assertThat(invokeIsShutdown(storage)).isFalse();
		storage.shutdown();
		assertThat(invokeIsShutdown(storage)).isTrue();
	}

	@Test
	void shutdownHandlesNullAndUninitializedRepositories() {
		QueryStorage nullStorage = new QueryStorage((Repository) null);
		nullStorage.shutdown();
		assertThat(invokeIsShutdown(nullStorage)).isTrue();

		Repository repository = mock(Repository.class);
		when(repository.isInitialized()).thenReturn(false);
		QueryStorage uninitializedStorage = new QueryStorage(repository);
		uninitializedStorage.shutdown();
		assertThat(invokeIsShutdown(uninitializedStorage)).isTrue();
	}

	private static boolean invokeIsShutdown(QueryStorage storage) {
		try {
			Method method = QueryStorage.class.getDeclaredMethod("isShutdown");
			method.setAccessible(true);
			return (boolean) method.invoke(storage);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Could not invoke isShutdown", e);
		}
	}
